import { prisma } from "@/lib/prisma";
import { DollarSign, ShoppingCart, Calendar, TrendingUp, History } from "lucide-react";
import UndoSaleButton from "@/components/UndoSaleButton";
import { auth } from "@/lib/auth";

export default async function SalesDashboardPage() {
  const session = await auth();
  const isAdmin = session?.user?.role === 'ADMIN';

  const sales = await prisma.sale.findMany({
    include: {
      user: true,
      items: {
        include: {
          product: true
        }
      }
    },
    orderBy: { createdAt: "desc" }
  });

  const totalRevenue = sales.reduce((acc, sale) => acc + sale.total, 0);
  const totalItemsSold = await prisma.saleItem.aggregate({
    _sum: { quantity: true }
  });

  const topProducts = await prisma.saleItem.groupBy({
    by: ['productId'],
    _sum: {
      quantity: true,
    },
    orderBy: {
      _sum: {
        quantity: 'desc'
      }
    },
    take: 10
  });

  const topProductsDetails = await Promise.all(
    topProducts.map(async (item) => {
      const product = await prisma.product.findUnique({
        where: { id: item.productId }
      });
      return {
        name: product?.name || "Desconhecido",
        quantity: item._sum.quantity,
        revenue: (item._sum.quantity || 0) * (product?.price || 0)
      };
    })
  );

  return (
    <div className="space-y-10 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
        <div className="space-y-1">
          <div className="flex items-center gap-2 text-scout-blue font-black uppercase text-[10px] tracking-[0.4em]">
            <History className="w-3 h-3" />
            Análise de Operações
          </div>
          <h1 className="text-4xl font-black text-gray-900 tracking-tight">Relatórios de Vendas</h1>
          <p className="text-gray-500 font-medium">Acompanhamento de faturamento e fluxo de saída</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm flex items-center gap-6 group hover:border-scout-green/20 transition-all">
          <div className="bg-scout-green/10 w-16 h-16 rounded-2xl flex items-center justify-center text-scout-green group-hover:scale-110 transition-transform">
            <DollarSign className="w-8 h-8" />
          </div>
          <div>
            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">Receita Total</p>
            <p className="text-3xl font-black text-gray-900">R$ {totalRevenue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm flex items-center gap-6 group hover:border-scout-blue/20 transition-all">
          <div className="bg-scout-blue/10 w-16 h-16 rounded-2xl flex items-center justify-center text-scout-blue group-hover:scale-110 transition-transform">
            <ShoppingCart className="w-8 h-8" />
          </div>
          <div>
            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">Itens Saídos</p>
            <p className="text-3xl font-black text-gray-900">{totalItemsSold._sum.quantity || 0}</p>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm flex items-center gap-6 group hover:border-scout-yellow/20 transition-all">
          <div className="bg-scout-yellow/10 w-16 h-16 rounded-2xl flex items-center justify-center text-amber-600 group-hover:scale-110 transition-transform">
            <Calendar className="w-8 h-8" />
          </div>
          <div>
            <p className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">Atendimentos</p>
            <p className="text-3xl font-black text-gray-900">{sales.length}</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 space-y-6">
          <h2 className="text-2xl font-black text-gray-900 flex items-center gap-3">
            Histórico Recente
          </h2>
          <div className="bg-white rounded-[2rem] border border-gray-100 shadow-sm overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-gray-50/50 text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] border-b border-gray-100">
                    <th className="py-5 px-8">Data/Hora</th>
                    <th className="py-5 px-8">Resumo dos Itens</th>
                    <th className="py-5 px-8">Operador</th>
                    <th className="py-5 px-8 text-right">Total</th>
                    <th className="py-5 px-8 text-center">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                  {sales.map((sale) => (
                    <tr key={sale.id} className="hover:bg-gray-50/30 transition-colors">
                      <td className="py-6 px-8 text-sm font-medium text-gray-600">
                        {new Date(sale.createdAt).toLocaleString('pt-BR', { dateStyle: 'short', timeStyle: 'short' })}
                      </td>
                      <td className="py-6 px-8">
                        <div className="text-xs text-gray-500 max-w-[200px] truncate font-medium">
                          {sale.items.map(i => `${i.quantity}x ${i.product.name}`).join(', ')}
                        </div>
                      </td>
                      <td className="py-6 px-8">
                        <span className="text-xs font-black uppercase text-scout-blue bg-scout-blue/5 px-3 py-1 rounded-full">
                          {sale.user.name?.split(' ')[0]}
                        </span>
                      </td>
                      <td className="py-6 px-8 text-right font-black text-gray-900">
                        R$ {sale.total.toFixed(2)}
                      </td>
                      <td className="py-6 px-8 text-center">
                        {isAdmin && <UndoSaleButton saleId={sale.id} />}
                      </td>
                    </tr>
                  ))}
                  {sales.length === 0 && (
                    <tr>
                      <td colSpan={5} className="py-24 text-center text-gray-400 font-medium italic uppercase tracking-widest opacity-50">
                        Nenhum registro de venda
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <h2 className="text-2xl font-black text-gray-900 flex items-center gap-3">
            Produtos em Alta
          </h2>
          <div className="bg-white rounded-[2rem] border border-gray-100 shadow-sm p-8 space-y-8">
            {topProductsDetails.map((item, index) => (
              <div key={item.name} className="flex flex-col gap-2">
                <div className="flex justify-between items-end">
                  <div>
                    <p className="font-bold text-gray-900 leading-tight">{item.name}</p>
                    <p className="text-[10px] font-black uppercase text-scout-green">{item.quantity} unidades</p>
                  </div>
                  <p className="font-black text-gray-900 text-sm italic">R$ {item.revenue.toFixed(2)}</p>
                </div>
                <div className="w-full bg-gray-100 h-2 rounded-full overflow-hidden">
                  <div 
                    className="bg-scout-blue h-full rounded-full transition-all duration-1000" 
                    style={{ width: `${(item.quantity! / (topProductsDetails[0].quantity || 1)) * 100}%` }}
                  />
                </div>
              </div>
            ))}
            {topProductsDetails.length === 0 && (
              <div className="py-12 text-center text-gray-400 font-medium italic uppercase tracking-widest opacity-50 text-xs">
                Aguardando dados...
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
